import pytest
import requests

def test_reset_password_valid_token_and_2fa_succeeds(
    fresh_reset_token,   # <fixture> returns {'token': str, 'employee_id': str}
    valid_2fa_code,      # <fixture> returns current TOTP code for employee
    compliant_password,  # <fixture> returns policy-compliant password string
    active_session_token # <fixture> returns a pre-existing session token
):
    payload = {
        "token": fresh_reset_token["token"],
        "new_password": compliant_password,
        "totp_code": valid_2fa_code
    }
    resp = requests.post(
        "http://hr-app/password/reset",
        json=payload
    )
    assert resp.status_code == 200
    assert resp.json().get("status") == "password_updated"

    # Verify old session is invalidated
    session_check = requests.get(
        "http://hr-app/api/me",
        headers={"Authorization": f"Bearer {active_session_token}"}
    )
    assert session_check.status_code == 401

    # Verify new password works
    login_resp = <helper_fn>.login(
        fresh_reset_token["employee_id"], compliant_password
    )
    assert login_resp.status_code == 200

import pytest
import requests

def test_reset_password_sessions_invalidated_after_successful_reset(
    fresh_reset_token,
    valid_2fa_code,
    compliant_password,
    multiple_active_sessions # <fixture> returns list of session token strings
):
    payload = {
        "token": fresh_reset_token["token"],
        "new_password": compliant_password,
        "totp_code": valid_2fa_code
    }
    resp = requests.post(
        "http://hr-app/password/reset",
        json=payload
    )
    assert resp.status_code == 200

    for session_token in multiple_active_sessions:
        check = requests.get(
            "http://hr-app/api/me",
            headers={"Authorization": f"Bearer {session_token}"}
        )
        assert check.status_code == 401, (
            f"Session {session_token[:8]}... must be invalidated"
        )
